def find_urls(s: str) -> list[str]:
    urls = []
    start = 0
    while True:
        start = s.find('http://', start)
        if start == -1:
            break
        end = s.find('/', start)
        if end == -1:
            end = len(s)
        urls.append(s[start:end])
        start = end
    return urls

